(window.webpackJsonp=window.webpackJsonp||[]).push([[72],{544:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\nOrbitControls 是 Three.js 中最常用的相机控制器，但默认配置往往无法满足复杂业务需求。本文分享在 3D 机房项目中对 OrbitControls 的深度定制经验，包括视角限制、平滑飞行动画、多视角切换以及触屏适配等实用技巧。\n&lt;/div&gt;</p>\n<h2>一、基础配置优化</h2>\n<p>默认的 OrbitControls 配置适合通用场景，但在机房项目中需要更精细的控制：</p>\n<pre><code class=\"language-javascript\">import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls'\n\nconst controls = new OrbitControls(camera, renderer.domElement)\n\n// 启用惯性阻尼\ncontrols.enableDamping = true\ncontrols.dampingFactor = 0.08\n\n// 限制垂直旋转角度，防止相机穿过地面\ncontrols.maxPolarAngle = Math.PI / 2.1\ncontrols.minPolarAngle = Math.PI / 8\n\n// 限制缩放范围\ncontrols.minDistance = 5\ncontrols.maxDistance = 80\n\n// 限制平移范围，防止拖出场景边界\ncontrols.maxTargetRadius = 30\n\n// 旋转速度\ncontrols.rotateSpeed = 0.8\n// 缩放速度\ncontrols.zoomSpeed = 1.2\n// 平移速度\ncontrols.panSpeed = 0.6\n\n// 禁用键盘控制（防止与页面快捷键冲突）\ncontrols.enableKeys = false\n</code></pre>\n<h2>二、平滑飞行动画</h2>\n<p>点击设备后，相机需要平滑飞行到设备附近。直接修改 <code>camera.position</code> 会导致跳变，我们使用 GSAP 实现平滑过渡：</p>\n<pre><code class=\"language-javascript\">function flyTo(targetPosition, lookAtPosition, duration = 1.5) {\n  // 禁用控制器，防止冲突\n  controls.enabled = false\n\n  // 计算相机目标位置（设备上方偏后）\n  const cameraTarget = new THREE.Vector3(\n    targetPosition.x + 5,\n    targetPosition.y + 5,\n    targetPosition.z + 5\n  )\n\n  // 相机位置动画\n  gsap.to(camera.position, {\n    x: cameraTarget.x,\n    y: cameraTarget.y,\n    z: cameraTarget.z,\n    duration,\n    ease: 'power2.inOut',\n    onUpdate: () =&gt; {\n      camera.lookAt(controls.target)\n    }\n  })\n\n  // 注视点动画\n  gsap.to(controls.target, {\n    x: lookAtPosition.x,\n    y: lookAtPosition.y,\n    z: lookAtPosition.z,\n    duration,\n    ease: 'power2.inOut',\n    onComplete: () =&gt; {\n      controls.enabled = true\n    }\n  })\n}\n</code></pre>\n<h2>三、预设视角切换</h2>\n<p>机房场景通常需要多个预设视角：</p>\n<pre><code class=\"language-javascript\">const viewPresets = {\n  // 全景俯视\n  overview: {\n    position: new THREE.Vector3(0, 50, 0.1),\n    target: new THREE.Vector3(0, 0, 0)\n  },\n  // 正面视图\n  front: {\n    position: new THREE.Vector3(0, 10, 40),\n    target: new THREE.Vector3(0, 0, 0)\n  },\n  // 侧面视图\n  side: {\n    position: new THREE.Vector3(40, 10, 0),\n    target: new THREE.Vector3(0, 0, 0)\n  },\n  // 45度常规视角\n  perspective: {\n    position: new THREE.Vector3(25, 20, 25),\n    target: new THREE.Vector3(0, 0, 0)\n  }\n}\n\nfunction switchView(viewName) {\n  const preset = viewPresets[viewName]\n  if (!preset) return\n  flyTo(preset.position, preset.target, 1.2)\n}\n</code></pre>\n<h3>视角切换按钮组</h3>\n<pre><code class=\"language-vue\">&lt;template&gt;\n  &lt;div class=&quot;view-switcher&quot;&gt;\n    &lt;button \n      v-for=&quot;(view, name) in viewPresets&quot; \n      :key=&quot;name&quot;\n      :class=&quot;{ active: currentView === name }&quot;\n      @click=&quot;switchView(name)&quot;\n    &gt;\n      {{ viewLabels[name] }}\n    &lt;/button&gt;\n  &lt;/div&gt;\n&lt;/template&gt;\n</code></pre>\n<h2>四、双击聚焦</h2>\n<p>双击设备自动聚焦，是提升用户体验的重要细节：</p>\n<pre><code class=\"language-javascript\">let clickTimer = null\n\nrenderer.domElement.addEventListener('click', (event) =&gt; {\n  if (clickTimer) {\n    // 双击\n    clearTimeout(clickTimer)\n    clickTimer = null\n    handleDoubleClick(event)\n  } else {\n    // 等待是否有第二次点击\n    clickTimer = setTimeout(() =&gt; {\n      clickTimer = null\n      handleSingleClick(event)\n    }, 250)\n  }\n})\n\nfunction handleDoubleClick(event) {\n  const intersect = raycast(event)\n  if (!intersect) return\n\n  const deviceMesh = findParentDevice(intersect.object)\n  if (!deviceMesh) return\n\n  // 聚焦到设备\n  const boundingBox = new THREE.Box3().setFromObject(deviceMesh)\n  const center = boundingBox.getCenter(new THREE.Vector3())\n  const size = boundingBox.getSize(new THREE.Vector3())\n  const maxDim = Math.max(size.x, size.y, size.z)\n\n  flyTo(\n    center.clone().add(new THREE.Vector3(maxDim, maxDim, maxDim)),\n    center,\n    1\n  )\n}\n</code></pre>\n<h2>五、触屏设备适配</h2>\n<p>大屏项目偶尔需要支持触屏操作：</p>\n<pre><code class=\"language-javascript\">// 判断触屏设备\nconst isTouchDevice = 'ontouchstart' in window\n\nif (isTouchDevice) {\n  // 调整触摸灵敏度\n  controls.rotateSpeed = 0.4\n  controls.panSpeed = 0.3\n  controls.zoomSpeed = 0.8\n\n  // 禁用右键平移，使用双指平移\n  controls.mouseButtons = {\n    LEFT: THREE.MOUSE.ROTATE,\n    MIDDLE: THREE.MOUSE.DOLLY,\n    RIGHT: null\n  }\n\n  controls.touches = {\n    ONE: THREE.TOUCH.ROTATE,\n    TWO: THREE.TOUCH.DOLLY_PAN\n  }\n}\n</code></pre>\n<h2>六、总结</h2>\n<p>OrbitControls 的深度定制让 3D 场景的交互体验质的飞跃：</p>\n<ul>\n<li><strong>视角限制</strong>：防止用户将相机拖到不合理的位置</li>\n<li><strong>飞行动画</strong>：让视角切换丝滑自然</li>\n<li><strong>预设视角</strong>：快速切换到常用观察角度</li>\n<li><strong>双击聚焦</strong>：降低用户定位设备的成本</li>\n<li><strong>触屏适配</strong>：拓展大屏触控操作场景</li>\n</ul>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);